{"file_path":"/home/user/workspace/app/actions.ts","content":"'use server';

import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from '@/app/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const body = formData.get('body') as string;

  if (!title || !body) {
    throw new Error('Title and body are required');
  }

  addPost(title, body);

  // Invalidate all data tagged with 'posts' — the fetch in page.tsx
  // uses next: { tags: ['posts'] }, so its cached response is discarded
  // and the next render will wait for fresh data.
  revalidateTag('posts');

  // Redirect back to the page. Because the 'posts' cache tag has been
  // invalidated, the re-render triggered by this redirect will not serve
  // stale data — it re-fetches from the API handler synchronously.
  redirect('/');
}
"}

