{"file_path":"/home/user/workspace/app/page.tsx","content":"import { createPost } from '@/app/actions';
import type { Post } from '@/app/lib/posts';

export default async function Home() {
  // The fetch response is cached under the "posts" tag.
  // After createPost() calls revalidateTag('posts'), this cached entry is
  // invalidated, so the next server render must re-fetch fresh data.
  const res = await fetch('http://localhost:3000/api/posts', {
    next: { tags: ['posts'] },
  });
  const posts: Post[] = await res.json();

  return (
    <main>
      <h1>Posts</h1>

      <form action={createPost}>
        <input name="title" placeholder="Title" required />
        <br />
        <textarea name="body" placeholder="Body" required />
        <br />
        <button type="submit">Create Post</button>
      </form>

      {posts.length === 0 ? (
        <p>No posts yet. Create one above!</p>
      ) : (
        <ul>
          {posts.map((post) => (
            <li key={post.id}>
              <h2>{post.title}</h2>
              <p>{post.body}</p>
              <small>{post.createdAt}</small>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}
"}

